import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import Button from './Button';
import { 
  RotateCcw, BrainCircuit, Check, X, Clock, Flag, ChevronLeft, 
  ChevronRight, LayoutGrid, Image as ImageIcon, Zap, Hash, Filter, 
  CheckCircle2, Lightbulb, Shuffle, Maximize2, Play, Trophy, Target, 
  Eye, List, BarChart3, AlertTriangle, Medal
} from 'lucide-react';

const SESSION_KEY = 'anatomy_quiz_session_v1';
const SETTINGS_KEY = 'anatomy_quiz_settings_v1';
const MISTAKES_KEY = 'anatomy_quiz_mistakes_v1';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
}

const Quiz: React.FC<QuizProps> = ({ data }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('exam');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [zoomedImage, setZoomedImage] = useState<string | null>(null);

  // Settings
  const [questionCount, setQuestionCount] = useState(25);
  const [selectedGroups, setSelectedGroups] = useState<string[]>([]);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [showExplanations, setShowExplanations] = useState(true);
  const [shuffleQuestions, setShuffleQuestions] = useState(true);

  // Mobile Nav State
  const [isMobileNavOpen, setIsMobileNavOpen] = useState(false);
  const [imgError, setImgError] = useState(false);
  const [mistakesHistory, setMistakesHistory] = useState<string[]>([]);

  useEffect(() => {
    // Load state logic... (نفس المنطق السابق لضبط الإعدادات واسترجاع الجلسة)
    const savedMistakes = localStorage.getItem(MISTAKES_KEY);
    if (savedMistakes) setMistakesHistory(JSON.parse(savedMistakes));
  }, []);

  // Helper functions for start/generate quiz (نفس المنطق السابق)
  const generateQuiz = (pool: Question[], count: number) => {
    let selectedQuestions = [...pool];
    if (shuffleQuestions) selectedQuestions.sort(() => Math.random() - 0.5);
    selectedQuestions = selectedQuestions.slice(0, count);

    return selectedQuestions.map(q => {
      const correct = q.answerText;
      let options = q.options && q.options.length >= 4 ? q.options : [correct, "Distractor A", "Distractor B", "Distractor C"];
      return {
        id: q.id,
        data: q,
        options: options.sort(() => Math.random() - 0.5),
        correctOption: correct,
        userAnswer: null,
        isFlagged: false
      } as QuizQuestion;
    });
  };

  const startQuiz = () => {
    let pool = data.filter(q => q.answerText);
    if (selectedGroups.length > 0) pool = pool.filter(q => selectedGroups.includes(q.category));
    if (showImagesOnly) pool = pool.filter(q => q.questionImage);
    const newQuestions = generateQuiz(pool, Math.min(questionCount, pool.length));
    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(newQuestions.length * 60);
    setView('playing');
  };

  const currentQ = questions[currentQIndex];

  const QuestionNavigator = () => (
    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full">
      <div className="p-4 bg-slate-50 border-b border-slate-200">
        <div className="flex justify-between items-center mb-2">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Progress</span>
          <span className="text-xs font-bold text-blue-600">{questions.filter(q => q.userAnswer).length}/{questions.length}</span>
        </div>
        <div className="w-full bg-slate-200 h-1.5 rounded-full overflow-hidden">
          <div 
            className="bg-blue-500 h-full transition-all duration-500" 
            style={{ width: `${(questions.filter(q => q.userAnswer).length / questions.length) * 100}%` }}
          />
        </div>
      </div>
      <div className="flex-1 overflow-y-auto p-3 custom-scrollbar">
        <div className="grid grid-cols-5 gap-1.5">
          {questions.map((q, idx) => (
            <button
              key={q.id}
              onClick={() => { setCurrentQIndex(idx); setIsMobileNavOpen(false); }}
              className={`aspect-square rounded-lg border flex items-center justify-center text-xs font-black transition-all ${
                idx === currentQIndex ? 'ring-2 ring-blue-500 bg-blue-50 text-blue-700' : 
                q.userAnswer ? 'bg-blue-600 border-blue-600 text-white' : 'bg-white text-slate-400'
              }`}
            >
              {idx + 1}
            </button>
          ))}
        </div>
      </div>
      <div className="p-3 border-t border-slate-100">
        <button 
          onClick={() => setView('results')}
          className="w-full py-3 bg-slate-900 text-white rounded-xl font-black text-xs uppercase tracking-widest hover:bg-blue-600 transition-all"
        >
          Submit Exam
        </button>
      </div>
    </div>
  );

  if (view === 'setup') {
    return (
      <div className="h-full overflow-y-auto p-4 md:p-8 bg-slate-50 flex items-center justify-center">
        <div className="w-full max-w-2xl bg-white rounded-3xl shadow-xl p-6 md:p-10 space-y-8 animate-in fade-in zoom-in-95 duration-500">
          <div className="text-center space-y-2">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Assessment Setup</h2>
            <p className="text-slate-500 text-sm">Select your topics and mode to begin.</p>
          </div>

          {/* Settings UI... (مبسط للموبايل) */}
          <div className="space-y-4">
             <button onClick={startQuiz} className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-xl shadow-lg shadow-blue-200 active:scale-95 transition-all">
                Start Session
             </button>
          </div>
        </div>
      </div>
    );
  }

  if (view === 'playing' || view === 'review') {
    return (
      <div className="h-[calc(100vh-4rem)] md:h-[calc(100vh-5rem)] flex flex-col w-full bg-slate-50 overflow-hidden relative">
        {/* Navigator Drawer for Mobile */}
        {isMobileNavOpen && (
          <div className="fixed inset-0 z-50 bg-slate-900/40 backdrop-blur-sm lg:hidden" onClick={() => setIsMobileNavOpen(false)}>
             <div className="absolute right-0 top-0 bottom-0 w-64 bg-white shadow-2xl animate-in slide-in-from-right duration-300" onClick={e => e.stopPropagation()}>
                <QuestionNavigator />
             </div>
          </div>
        )}

        <div className="max-w-[1400px] mx-auto w-full h-full flex gap-4 p-2 md:p-4 overflow-hidden">
           <div className="flex-1 flex flex-col h-full gap-2 md:gap-4 min-w-0">
              {/* Question Header - More Compact */}
              <div className="flex justify-between items-center bg-white p-2 md:p-3 rounded-xl border border-slate-200 shadow-sm shrink-0">
                 <div className="flex items-center gap-2">
                    <span className="px-2 py-0.5 bg-slate-900 text-white rounded-md text-[10px] font-black">Q {currentQIndex + 1}</span>
                    <span className="text-[10px] font-bold text-slate-400 truncate max-w-[120px] md:max-w-xs uppercase">{currentQ.data.category}</span>
                 </div>
                 <div className="flex items-center gap-2">
                    <button onClick={() => setIsMobileNavOpen(true)} className="lg:hidden p-2 rounded-lg bg-slate-50 text-slate-600"><List size={18} /></button>
                    {mode === 'exam' && <span className="font-mono font-black text-xs md:text-sm text-slate-700 bg-slate-100 px-2 py-1 rounded-md">{formatTime(timeLeft)}</span>}
                 </div>
              </div>

              {/* Question Body - Optimized Padding */}
              <div className="flex-1 bg-white rounded-2xl md:rounded-3xl border border-slate-200 shadow-sm overflow-hidden flex flex-col relative">
                 <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar">
                    <div className="max-w-3xl mx-auto space-y-4 md:space-y-8">
                       <h3 className="text-base md:text-2xl font-bold text-slate-900 leading-tight" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />

                       {currentQ.data.questionImage && !imgError && (
                          <div className="w-full flex justify-center py-2">
                             <img 
                               src={currentQ.data.questionImage} 
                               className="max-h-[180px] md:max-h-[300px] object-contain rounded-xl cursor-zoom-in"
                               onClick={() => setZoomedImage(currentQ.data.questionImage!)}
                               onError={() => setImgError(true)}
                             />
                          </div>
                       )}

                       <div className="grid grid-cols-1 gap-2 md:gap-3">
                          {currentQ.options.map((option, idx) => {
                            const isSelected = currentQ.userAnswer === option;
                            const isCorrect = option === currentQ.correctOption;
                            const showResult = view === 'review' || (mode === 'practice' && !!currentQ.userAnswer);

                            let btnStyle = "border-2 border-slate-100 hover:border-blue-200 bg-white";
                            if (showResult) {
                               if (isCorrect) btnStyle = "border-emerald-500 bg-emerald-50 text-emerald-900";
                               else if (isSelected) btnStyle = "border-red-500 bg-red-50 text-red-900";
                               else btnStyle = "border-slate-50 opacity-50";
                            } else if (isSelected) {
                               btnStyle = "border-blue-600 bg-blue-50 text-blue-900 ring-1 ring-blue-600";
                            }

                            return (
                              <button
                                key={idx}
                                onClick={() => !showResult && setQuestions(prev => {
                                  const copy = [...prev];
                                  copy[currentQIndex].userAnswer = option;
                                  return copy;
                                })}
                                className={`w-full p-3 md:p-4 rounded-xl text-left transition-all flex items-start gap-3 md:gap-4 ${btnStyle}`}
                              >
                                <span className="w-6 h-6 shrink-0 rounded-md bg-slate-100 flex items-center justify-center text-[10px] font-black">{String.fromCharCode(65 + idx)}</span>
                                <span className="text-sm md:text-base font-semibold leading-tight">{option}</span>
                              </button>
                            );
                          })}
                       </div>
                    </div>
                 </div>

                 {/* Footer Navigation */}
                 <div className="p-2 md:p-4 border-t border-slate-100 bg-white flex justify-between gap-2">
                    <button 
                      onClick={() => setCurrentQIndex(prev => prev - 1)}
                      disabled={currentQIndex === 0}
                      className="flex-1 md:flex-none px-4 py-3 rounded-xl font-bold text-slate-500 disabled:opacity-20 flex items-center justify-center gap-1 text-xs"
                    >
                       <ChevronLeft size={16} /> Prev
                    </button>
                    {currentQIndex === questions.length - 1 ? (
                      <button onClick={() => setView('results')} className="flex-1 md:flex-none px-6 py-3 bg-slate-900 text-white rounded-xl font-black text-xs uppercase tracking-wider">Finish</button>
                    ) : (
                      <button 
                        onClick={() => setCurrentQIndex(prev => prev + 1)}
                        className="flex-1 md:flex-none px-6 py-3 bg-blue-600 text-white rounded-xl font-black text-xs uppercase tracking-wider flex items-center justify-center gap-1"
                      >
                        Next <ChevronRight size={16} />
                      </button>
                    )}
                 </div>
              </div>
           </div>

           {/* Desktop Navigator Sidebar */}
           <div className="hidden lg:block w-64 shrink-0">
              <QuestionNavigator />
           </div>
        </div>
        {zoomedImage && (
          <div className="fixed inset-0 z-[100] bg-black/90 flex items-center justify-center p-4" onClick={() => setZoomedImage(null)}>
             <img src={zoomedImage} className="max-w-full max-h-full object-contain" />
             <button className="absolute top-4 right-4 text-white"><X size={32} /></button>
          </div>
        )}
      </div>
    );
  }

  return null;
};

export default Quiz;

