import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Flashcards from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import QuestionBuilder from './components/QuestionBuilder';
import { AppMode, Question } from './types';

// UNIFIED MODULAR DATA IMPORTS
import { questions as ch1Data } from './hooks/data_ch1';
import { questions as ch3Data } from './hooks/data_ch3';
import { questions as ch4Data } from './hooks/data_ch4';
import { questions as ch6Data } from './hooks/data_ch6';
import { questions as ch7Data } from './hooks/data_ch7';
import { questions as ch8Data } from './hooks/data_ch8';
import { questions as ch9Data } from './hooks/data_ch9';
import { questions as ch10Data } from './hooks/data_ch10';
import { questions as ch11Data } from './hooks/data_ch11';

import { DatabaseZap } from 'lucide-react';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.FLASHCARDS);
  const [isSyncing, setIsSyncing] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v4');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v4', JSON.stringify(userVault));
    if (userVault.length > 0) {
        setIsSyncing(true);
        const timer = setTimeout(() => setIsSyncing(false), 1200);
        return () => clearTimeout(timer);
    }
  }, [userVault]);

  const allQuestions = useMemo(() => {
    const uniqueQuestions: Question[] = [];
    const seenIds = new Set<string>();

    // 1. User Priority
    userVault.forEach(q => { uniqueQuestions.push(q); seenIds.add(q.id); });

    // 2. Full System Repository (900+ Questions)
    const systemChapters = [
        ch1Data, ch3Data, ch4Data, ch6Data, 
        ch7Data, ch8Data, ch9Data, ch10Data, ch11Data
    ];

    systemChapters.flat().forEach(q => {
        if (!seenIds.has(q.id)) {
            uniqueQuestions.push(q);
            seenIds.add(q.id);
        }
    });

    return uniqueQuestions;
  }, [userVault]);

  const existingCategories = useMemo(() => {
    return Array.from(new Set(allQuestions.map(q => q.category))).sort();
  }, [allQuestions]);

  const handleSaveQuestion = (q: Question) => {
    setUserVault(prev => {
      const exists = prev.find(item => item.id === q.id);
      if (exists) return prev.map(item => item.id === q.id ? q : item);
      return [q, ...prev];
    });
    setEditingId(null);
    setCurrentMode(AppMode.LIST);
  };

  return (
    <div className="h-screen bg-slate-50 flex flex-col font-sans text-slate-900 overflow-hidden">
      <Header currentMode={currentMode} onModeChange={setCurrentMode} />

      {isSyncing && (
        <div className="fixed bottom-12 right-12 z-[100] animate-in fade-in slide-in-from-bottom-4">
          <div className="bg-slate-950 text-white px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 border border-slate-800">
            <DatabaseZap size={18} className="text-blue-400" />
            <span className="text-[10px] font-black uppercase tracking-widest">Vault Synced</span>
          </div>
        </div>
      )}

      <main className="flex-1 relative overflow-hidden">
        {currentMode === AppMode.FLASHCARDS && (
          <div className="h-full overflow-y-auto py-6"><Flashcards data={allQuestions} /></div>
        )}
        {currentMode === AppMode.QUIZ && (
          <div className="h-full"><Quiz data={allQuestions} /></div>
        )}
        {currentMode === AppMode.LIST && (
          <div className="h-full overflow-y-auto py-6">
            <QuestionList data={allQuestions} onExport={() => {}} onImport={() => {}} />
          </div>
        )}
        {currentMode === AppMode.STUDIO && (
          <div className="h-full overflow-y-auto">
            <QuestionBuilder 
              allQuestions={allQuestions} 
              editingId={editingId} 
              onSave={handleSaveQuestion} 
              onCancel={() => setCurrentMode(AppMode.LIST)} 
              existingCategories={existingCategories}
            />
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

